--
-- Name: bulk_insert_events(jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.bulk_insert_events(events jsonb) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    rec JSONB;
BEGIN
    FOR rec IN SELECT * FROM jsonb_array_elements(events)
    LOOP
        VALUES (
            rec->>'tenant_id',
            rec->>'user_id',
            rec->>'event_name',
            (rec->>'event_time')::timestamp,
            rec->'properties'
        );
    END LOOP;
END;
$$;


ALTER FUNCTION public.bulk_insert_events(events jsonb) OWNER TO postgres;

--
-- Name: delete_old_events(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_old_events() RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    DELETE FROM analytics.event
    WHERE event_time < NOW() - INTERVAL '90 days';
END;
$$;


ALTER FUNCTION public.delete_old_events() OWNER TO postgres;

