--
-- Name: validate_event(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.validate_event() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.event_name IS NULL THEN
        RAISE EXCEPTION 'event_name cannot be null';
    END IF;
    RETURN NEW;
END;
$$;


