--
-- Name: revenue_mv; Type: MATERIALIZED VIEW; Schema: analytics; Owner: postgres
--

CREATE MATERIALIZED VIEW analytics.revenue_mv AS
 SELECT tenant_id,
    date(event_time) AS event_date,
    sum(((properties ->> 'amount'::text))::integer) AS revenue
   FROM analytics.event
  WHERE (event_name = 'purchase'::text)
  GROUP BY tenant_id, (date(event_time))
  WITH NO DATA;


